import * as cepInterface from 'cep-interface';

export function openExternalLink(url) {
  cepInterface.openURLInDefaultBrowser(url);
}

/**
 * 通过 ExtendScript 调用 PS 原生文件夹选择对话框
 * @param {string} prompt 对话框提示文字
 * @returns {Promise<string|null>} 用户选择的文件夹路径，取消则返回 null
 */
export async function selectFolderDialog(prompt) {
  const result = await cepInterface.evalExtendscript(
    `(function(){ var f = Folder.selectDialog("${prompt || '请选择文件夹'}"); return f ? f.fsName : ""; })()`
  );
  return result && result !== 'null' && result !== '' ? result : null;
}
